#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007LL

typedef struct Edge {int to; long long w; struct Edge* next;} Edge;

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d", &N, &M);
        long long *Q = (long long*)calloc(N+1, sizeof(long long));
        for(int i=1;i<=N;i++) scanf("%lld", &Q[i]);
        Edge **head = (Edge**)calloc(N+1, sizeof(Edge*));
        for(int i=0;i<M;i++){
            int C0,X; scanf("%d %d", &C0, &X);
            for(int j=0;j<X;j++){
                long long w; int c; scanf("%lld %d", &w, &c);
                Edge* e = (Edge*)malloc(sizeof(Edge));
                e->to=c; e->w=w%MOD; e->next=head[C0]; head[C0]=e;
            }
        }
        for(int i=N;i>=1;i--){
            if(Q[i]==0) continue;
            for(Edge* e=head[i]; e; e=e->next){
                Q[e->to] = (Q[e->to] + Q[i]*e->w)%MOD;
            }
            Q[i]=0;
        }
        for(int i=1;i<=N;i++) printf("%lld\n", Q[i]);
        free(Q); free(head);
    }
    return 0;
}

