import sys
MOD = 1_000_000_007

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        Q = [0]*(N+1)
        for i in range(1, N+1):
            Q[i] = int(next(it))
        adj = [[] for _ in range(N+1)]
        for _ in range(M):
            C0 = int(next(it)); X = int(next(it))
            for __ in range(X):
                w = int(next(it)) % MOD
                c = int(next(it))
                adj[C0].append((c, w))
        for i in range(N, 0, -1):
            if Q[i]==0:
                continue
            qi = Q[i]
            for c, w in adj[i]:
                Q[c] = (Q[c] + qi * w) % MOD
            Q[i] = 0
        out_lines.extend(str(Q[i]) for i in range(1, N+1))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

